// Extract the text content from Claude's response
const content = $input.first().json.content;
let text = '';
if (Array.isArray(content)) {
  text = content.map(c => c.text || '').join('');
} else {
  text = String(content);
}

// Strip any accidental markdown fences
text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let recipe;
try {
  recipe = JSON.parse(text);
} catch(e) {
  throw new Error('Claude returned invalid JSON: ' + text.substring(0, 200));
}

// Validate required fields
const required = ['title','emoji','category','tags','description','ingredients','method','functionalMarkers'];
for (const f of required) {
  if (!recipe[f]) throw new Error(`Missing field: ${f}`);
}

return [{ json: recipe }];

// Decode existing file from base64
const fileData  = $('GitHub — Get Current recipes.json').first().json;
const sha       = fileData.sha;
const existing  = JSON.parse(Buffer.from(fileData.content.replace(/\n/g,''), 'base64').toString('utf-8'));

// Add new recipe with id and date
const newRecipe = $('Parse & Validate JSON').first().json;
const recipe = {
  id: existing.length + 1,
  dateAdded: new Date().toISOString().split('T')[0],
  ...newRecipe
};
existing.push(recipe);

// Encode updated array back to base64
const updated = Buffer.from(JSON.stringify(existing, null, 2)).toString('base64');

return [{ json: { sha, updatedBase64: updated, recipe } }];

const recipe = $('Build Updated File').first().json.recipe;
console.log(`✅ Recipe published: ${recipe.title} (id ${recipe.id}) on ${recipe.dateAdded}`);
return [{ json: { status: 'published', title: recipe.title, date: recipe.dateAdded } }];
